mapper.select:
select

from emp_leave_record


        and user_id = #{user_id}


        and create_time >= #{createTimeStart}


        and create_time <= #{createTimeEnd}


        and leave_start_time >= #{leaveStartTimeStart}


        and leave_start_time <= #{leaveStartTimeEnd}


        and leave_end_time >= #{leaveEndTimeStart}


        and leave_end_time <= #{leaveEndTimeEnd}


        and leave_type_code = #{leaveTypeCode}


        and status = #{status}

SELECT COUNT(*)
FROM emp_leave_record


        AND user_id = #{user_id}


        AND leave_type_code = #{leaveTypeCode}


        AND status = #{status}


        AND leave_start_time >= #{leaveStartTimeStart}


        AND leave_end_time <= #{leaveEndTimeEnd}

SELECT lr.id, lr.user_id, lr.create_time as createTime, lr.leave_start_time as leaveStartTime, lr.leave_end_time as leaveEndTime, lr.leave_reason as leaveReason, lr.leave_type_code as leaveTypeCode, lr.approve_user_id, lr.approve_time as approveTime, lr.approve_content as approveContent, lr.status, lr.real_end_time as realEndTime, COALESCE(e1.name, u1.name) as userName, COALESCE(e2.name, u2.name) as approveUserName, d.dict_item_value as leaveTypeName, CASE lr.status WHEN 0 THEN '草稿' WHEN 1 THEN '待审' WHEN 2 THEN '通过' WHEN 3 THEN '驳回' WHEN 9 THEN '销假' ELSE '未知' END as statusName FROM emp_leave_record lr LEFT JOIN sys_user u1 ON lr.user_id = u1.id LEFT JOIN emp e1 ON u1.id = e1.user_id LEFT JOIN sys_user u2 ON lr.approve_user_id = u2.id LEFT JOIN emp e2 ON u2.id = e2.user_id LEFT JOIN sys_dict d ON d.dict_type = '请假类型' AND d.dict_item_key = lr.leave_type_code
AND lr.user_id = #{user_id}
AND lr.leave_type_code = #{leaveTypeCode}
AND lr.status = #{status}
AND lr.leave_start_time >= #{leaveStartTimeStart}
AND lr.leave_end_time <= #{leaveEndTimeEnd}
ORDER BY lr.create_time DESC
